interface iIconArgs {
  icon: string;
  style: string;
  size: string;
  color: string;
  spin: boolean;
  rotate: number;
  flip: string;
}

const meta: Meta<iIconArgs> = {
  title: 'Icons/Playground',
  argTypes: {
    icon: {
      control: 'select',
      options: AVAILABLE_ICONS,
      description: 'Icon name',
    },
    style: {
      control: 'select',
      options: AVAILABLE_STYLES,
      description: 'Icon style',
    },
    size: {
      control: 'select',
      options: ['text-xs', 'text-sm', 'text-base', 'text-lg', 'text-xl', 'text-2xl', 'text-3xl', 'text-4xl', 'text-5xl', 'text-6xl', 'text-7xl', 'text-8xl', 'text-9xl'],
      description: 'Tailwind text size',
    },
    color: {
      control: 'color',
      description: 'Icon color',
    },
    spin: {
      control: 'boolean',
      description: 'Tailwind animate-spin',
    },
    rotate: {
      control: 'number',
      description: 'Rotation in degrees',
    },
    flip: {
      control: 'select',
      options: ['none', 'scale-x-[-1]', 'scale-y-[-1]'],
      description: 'Flip',
    },
  },
  args: {
    icon: 'diya',
    style: 'vi-solid',
    size: 'text-4xl',
    color: '#ffffff',
    spin: false,
    rotate: 0,
    flip: 'none',
  },
};

export default meta;
type iStory = StoryObj<iIconArgs>;

export const Playground: iStory = {
  render: (args) => {
    const spinClass = args.spin ? 'animate-spin' : '';
    const flipClass = args.flip === 'none' ? '' : args.flip;
    const classes = ['vi', args.style, `vi-${args.icon}`, args.size, spinClass, flipClass]
      .filter(Boolean)
      .join(' ');

    const rotateStyle = args.rotate ? `transform: rotate(${args.rotate}deg);` : '';
    const code = `&lt;i class="${classes}"&gt;&lt;/i&gt;`;

    return `
      <div class="flex flex-col items-center gap-6 p-8">
        <i class="${classes}" style="color: ${args.color}; ${rotateStyle}"></i>
        <code class="text-xs text-zinc-400 font-mono bg-zinc-800 px-3 py-1.5 rounded">${code}</code>
      </div>
    `;
  },
};

export const AllIcons: iStory = {
  argTypes: {
    icon: { table: { disable: true } },
    style: { table: { disable: true } },
    spin: { table: { disable: true } },
    rotate: { table: { disable: true } },
    flip: { table: { disable: true } },
  },
  render: (args) => {
    const styles = ['solid', 'outlined'];

    const grid = styles
      .map((style) => {
        const icons = AVAILABLE_ICONS.map(
          (name) => `
          <div class="flex flex-col items-center gap-2 p-4">
            <i class="vi vi-${style} vi-${name} ${args.size}" style="color: ${args.color};"></i>
            <span class="text-xs text-zinc-400 font-mono">vi-${style} vi-${name}</span>
          </div>
        `
        ).join('');

        return `
          <div class="mb-8">
            <h3 class="text-sm font-bold text-zinc-300 mb-4 uppercase tracking-wider">${style}</h3>
            <div class="flex flex-wrap gap-4">${icons}</div>
          </div>
        `;
      })
      .join('');

    return `<div class="p-8">${grid}</div>`;
  },
};

export const Sizes: iStory = {
  render: () => {
    const sizes = ['text-xs', 'text-sm', 'text-base', 'text-lg', 'text-xl', 'text-2xl', 'text-3xl', 'text-4xl', 'text-5xl', 'text-6xl', 'text-7xl', 'text-8xl'];

    const items = sizes
      .map((size) => `
        <div class="flex items-center gap-4 text-white">
          <i class="vi vi-solid vi-diya ${size}"></i>
          <i class="vi vi-outlined vi-diya ${size}"></i>
          <span class="text-xs text-zinc-400 font-mono">${size}</span>
        </div>
      `)
      .join('');

    return `<div class="flex flex-col gap-4 p-8">${items}</div>`;
  },
};

export const Colors: iStory = {
  render: () => {
    const colors = [
      'text-red-500',
      'text-amber-400',
      'text-green-500',
      'text-blue-500',
      'text-purple-500',
      'text-white',
    ];

    const items = colors
      .map((cls) => `
        <div class="flex items-center gap-4">
          <i class="vi vi-solid vi-diya text-3xl ${cls}"></i>
          <i class="vi vi-outlined vi-diya text-3xl ${cls}"></i>
          <span class="text-xs text-zinc-400 font-mono">${cls}</span>
        </div>
      `)
      .join('');

    return `<div class="flex flex-col gap-4 p-8">${items}</div>`;
  },
};

export const Redo: iStory = {
  argTypes: {
    icon: { table: { disable: true } },
    style: { table: { disable: true } },
    spin: { table: { disable: true } },
    rotate: { table: { disable: true } },
    flip: { table: { disable: true } },
  },
  render: (args) => {
    const redoIcons = [
      { style: 'solid', name: 'meenakshi-temple' },
      { style: 'solid', name: 'narasimha' },
      { style: 'solid', name: 'rangoli' },
      { style: 'solid', name: 'saraswati' },
      { style: 'solid', name: 'scroll-02' },
      { style: 'outlined', name: 'agni-dev' },
      { style: 'outlined', name: 'brahma' },
      { style: 'outlined', name: 'calendar-pongol' },
      { style: 'outlined', name: 'coin' },
      { style: 'outlined', name: 'golden-temple' },
      { style: 'outlined', name: 'hanumaan' },
      { style: 'outlined', name: 'mandala-02' },
      { style: 'outlined', name: 'meenakshi-temple' },
      { style: 'outlined', name: 'narasimha' },
      { style: 'outlined', name: 'red-fort' },
      { style: 'outlined', name: 'saraswati' },
      { style: 'outlined', name: 'scroll' },
      { style: 'outlined', name: 'scroll-03' },
      { style: 'outlined', name: 'temple' },
      { style: 'outlined', name: 'varaha' },
    ];

    const svgMap: Record<string, string> = REDO_SVG_MAP;

    const rows = redoIcons
      .map(({ style, name }) => {
        const key = `${style}/${name}`;
        const rawSvg = svgMap[key] || '';
        const inlineSvg = rawSvg
          .replace(/fill="currentColor"/g, `fill="${args.color}"`)
          .replace('<svg ', '<svg width="64" height="64" ');

        return `
          <tr style="border-bottom: 1px solid #333;">
            <td style="padding: 12px; text-align: center; vertical-align: middle;">
              <i class="vi vi-${style} vi-${name} text-5xl" style="color: ${args.color};"></i>
            </td>
            <td style="padding: 12px; text-align: center; vertical-align: middle;">
              ${inlineSvg}
            </td>
            <td style="padding: 12px; vertical-align: middle;">
              <span class="text-xs text-zinc-400 font-mono">vi-${style} vi-${name}</span>
            </td>
          </tr>
        `;
      })
      .join('');

    return `
      <div class="p-8">
        <h3 class="text-sm font-bold text-zinc-300 mb-6 uppercase tracking-wider">Redo Comparison — Font Glyph vs Original SVG (${redoIcons.length})</h3>
        <table style="border-collapse: collapse; width: 100%;">
          <thead>
            <tr style="border-bottom: 2px solid #555;">
              <th style="padding: 8px 12px; text-align: center; color: #aaa; font-size: 12px; text-transform: uppercase;">Font Glyph</th>
              <th style="padding: 8px 12px; text-align: center; color: #aaa; font-size: 12px; text-transform: uppercase;">Original SVG</th>
              <th style="padding: 8px 12px; text-align: left; color: #aaa; font-size: 12px; text-transform: uppercase;">Name</th>
            </tr>
          </thead>
          <tbody>${rows}</tbody>
        </table>
      </div>
    `;
  },
};

export const Workshop: iStory = {
  argTypes: {
    icon: { table: { disable: true } },
    style: { table: { disable: true } },
    flip: { table: { disable: true } },
  },
  render: (args) => {
    const current = { style: 'solid', name: 'hanumaan', file: 'Hanumaan - Solid.svg' };

    const spinClass = args.spin ? 'animate-spin' : '';
    const rotateStyle = args.rotate ? `transform: rotate(${args.rotate}deg);` : '';

    return `
      <div class="p-8">
        <h3 class="text-sm font-bold text-zinc-300 mb-6 uppercase tracking-wider">Workshop — vi-${current.style} vi-${current.name}</h3>
        <table style="border-collapse: collapse; width: 100%;">
          <thead>
            <tr style="border-bottom: 2px solid #555;">
              <th style="padding: 8px 16px; color: #aaa; font-size: 12px; text-transform: uppercase;">Original SVG File</th>
              <th style="padding: 8px 16px; color: #aaa; font-size: 12px; text-transform: uppercase;">Converted SVG</th>
              <th style="padding: 8px 16px; color: #aaa; font-size: 12px; text-transform: uppercase;">Font Glyph</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td style="padding: 24px; text-align: center; vertical-align: middle; background: #fff;">
                <img src="/icons-svg/${current.file}" width="128" height="128" alt="${current.name} original" />
              </td>
              <td style="padding: 24px; text-align: center; vertical-align: middle; background: #fff;">
                <img src="/icons/${current.style}/${current.name}.svg" width="128" height="128" alt="${current.name} converted" />
              </td>
              <td style="padding: 24px; text-align: center; vertical-align: middle; background: #fff;">
                <i class="vi vi-${current.style} vi-${current.name} ${args.size} ${spinClass}" style="color: ${args.color}; ${rotateStyle}"></i>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    `;
  },
};

