export const AllComparison: iStory = {
  argTypes: {
    icon: { table: { disable: true } },
    style: { table: { disable: true } },
    spin: { table: { disable: true } },
    rotate: { table: { disable: true } },
    flip: { table: { disable: true } },
  },
  render: (args) => {
    const styles = ['solid', 'outlined'];

    const sections = styles.map((style) => {
      const rows = AVAILABLE_ICONS.map((name) => {
        const key = `${style}/${name}`;
        const originalFile = FILE_MAP[key] || '';
        const hasOriginal = !!originalFile;

        return `
          <tr style="border-bottom: 1px solid #333;">
            <td style="padding: 8px 12px; text-align: center; vertical-align: middle; background: #fff; width: 80px;">
              ${hasOriginal ? `<img src="/icons-svg/${originalFile}" width="48" height="48" alt="${name}" />` : '<span style="color:#555;">—</span>'}
            </td>
            <td style="padding: 8px 12px; text-align: center; vertical-align: middle; background: #fff; width: 80px;">
              <img src="/icons/${style}/${name}.svg" width="48" height="48" alt="${name}" onerror="this.parentElement.innerHTML='<span style=color:#555>—</span>'" />
            </td>
            <td style="padding: 8px 12px; text-align: center; vertical-align: middle; background: #fff; width: 80px;">
              <i class="vi vi-${style} vi-${name} ${args.size}" style="color: #000;"></i>
            </td>
            <td style="padding: 8px 12px; vertical-align: middle;">
              <span class="text-xs text-zinc-400 font-mono">vi-${style} vi-${name}</span>
            </td>
          </tr>`;
      }).join('');

      return `
        <div class="mb-12">
          <h3 class="text-sm font-bold text-zinc-300 mb-4 uppercase tracking-wider">${style} (${AVAILABLE_ICONS.length})</h3>
          <table style="border-collapse: collapse; width: 100%;">
            <thead>
              <tr style="border-bottom: 2px solid #555;">
                <th style="padding: 4px 12px; color: #aaa; font-size: 11px; text-transform: uppercase;">Original</th>
                <th style="padding: 4px 12px; color: #aaa; font-size: 11px; text-transform: uppercase;">Converted</th>
                <th style="padding: 4px 12px; color: #aaa; font-size: 11px; text-transform: uppercase;">Font</th>
                <th style="padding: 4px 12px; color: #aaa; font-size: 11px; text-transform: uppercase; text-align: left;">Name</th>
              </tr>
            </thead>
            <tbody>${rows}</tbody>
          </table>
        </div>`;
    }).join('');

    return `<div class="p-8">${sections}</div>`;
  },
};

